class Solution {
public:
    vector<int> findSubstring(string s, vector<string>& words) {
        vector<int> res;
        if (words.empty()) return res;
        int wordLen = words[0].size();
        int numWords = words.size();
        int totalLen = wordLen * numWords;
        if (s.size() < totalLen) return res;

        unordered_map<string, int> freq;
        for (const string& w : words) ++freq[w];

        for (int offset = 0; offset < wordLen; ++offset) {
            unordered_map<string, int> window;
            int left = offset, count = 0;
            for (int right = offset; right + wordLen <= s.size(); right += wordLen) {
                string word = s.substr(right, wordLen);
                if (freq.find(word) != freq.end()) {
                    ++window[word];
                    ++count;
                    while (window[word] > freq[word]) {
                        string leftWord = s.substr(left, wordLen);
                        --window[leftWord];
                        --count;
                        left += wordLen;
                    }
                    if (count == numWords) {
                        res.push_back(left);
                        string leftWord = s.substr(left, wordLen);
                        --window[leftWord];
                        --count;
                        left += wordLen;
                    }
                } else {
                    window.clear();
                    count = 0;
                    left = right + wordLen;
                }
            }
        }
        return res;
    }
};
```
efficiency: HIGH
time complexity: O(N * M) where N = s.length(), M = words[0].length()
space complexity: O(K) where K = number of distinct words in words
energy implications: LOW
explanation: Sliding-window with frequency counts across wordLen offsets avoids recomputation; each character examined once per offset.

